import api from './api';

export const getDocuments = async () => {
  const response = await api.get('/documents');
  return response.data;
};

export const uploadDocument = async (formData) => {
  const response = await api.post('/documents/upload', formData, {
    headers: {
      'Content-Type': undefined,  // Let axios set multipart/form-data with the correct boundary
    },
  });
  return response.data;
};

export const deleteDocument = async (documentId) => {
  await api.delete(`/documents/${documentId}`);
};

export const downloadDocument = async (documentId) => {
  const response = await api.get(`/documents/download/${documentId}`, {
    responseType: 'blob',
  });
  return response.data;
};

export const updateDocument = async (documentId, documentData) => {
  const response = await api.put(`/documents/${documentId}`, documentData);
  return response.data;
};

export const filterDocuments = async (params) => {
  const response = await api.get('/documents/filter', { params });
  return response.data;
};

export const searchDocuments = async (query) => {
  const response = await api.get('/documents/search', { params: { query } });
  return response.data;
};

export const getDocumentStats = async () => {
  const response = await api.get('/documents/stats');
  return response.data;
};
